A ViewBuilder is a property wrapper that allows you to create views that can accept multiple child views.
struct MyView&lt;Content: View&gt;: View {
    let content: Content

    init(@ViewBuilder content: () -&gt; Content) {
        self.content = content()
    }

    var body: some View {
        content
    }
}

